 42→@OptIn(ExperimentalMaterial3Api::class)
 43→@Composable
 44→fun TimelineScreen(
 45→    onPostClick: (String) -> Unit,
 46→    onProfileClick: (String) -> Unit,
 47→    onComposeClick: (String?) -> Unit,
 48→    onQuoteClick: (String) -> Unit = {},
 49→    viewModel: TimelineViewModel = hiltViewModel()
 50→) {
 51→    val uiState by viewModel.uiState.collectAsState()
 52→    val timelineMaxLength by viewModel.preferencesManager.timelineMaxLength.collectAsState(initial = 0)
 53→    val listState = rememberLazyListState()
 54→    val context = LocalContext.current
 55→    val lifecycleOwner = LocalLifecycleOwner.current
 56→
 57→    DisposableEffect(lifecycleOwner) {
 58→        val observer = LifecycleEventObserver { _, event ->
 59→            if (event == Lifecycle.Event.ON_RESUME) {
 60→                viewModel.refreshIfStale()
 61→            }
 62→        }
 63→        lifecycleOwner.lifecycle.addObserver(observer)
 64→        onDispose { lifecycleOwner.lifecycle.removeObserver(observer) }
 65→    }
 66→
 67→    val shouldLoadMore by remember {
 68→        derivedStateOf {
 69→            val lastVisibleItem = listState.layoutInfo.visibleItemsInfo.lastOrNull()
 70→            lastVisibleItem != null && lastVisibleItem.index >= listState.layoutInfo.totalItemsCount - 3
 71→        }
 72→    }
 73→
 74→    LaunchedEffect(shouldLoadMore) {
 75→        if (shouldLoadMore && uiState.hasNextPage && !uiState.isLoadingMore) {
 76→            viewModel.loadMore()
 77→        }
 78→    }
 79→
 80→    Scaffold(
 81→        contentWindowInsets = WindowInsets(0),
 82→        topBar = {
 83→            CompactTopBar(title = stringResource(R.string.personal_timeline))
 84→        },
 85→        floatingActionButton = {
 86→            FloatingActionButton(
 87→                onClick = { onComposeClick(null) },
 88→                containerColor = MaterialTheme.colorScheme.primary
 89→            ) {
 90→                Icon(
 91→                    imageVector = Icons.Default.Add,
 92→                    contentDescription = stringResource(R.string.compose)
 93→                )
 94→            }
 95→        }
 96→    ) { paddingValues ->
 97→        Box(
 98→            modifier = Modifier
 99→                .fillMaxSize()
100→                .padding(paddingValues)
101→        ) {
102→            when {
103→                uiState.isLoading && uiState.posts.isEmpty() -> {
104→                    FullScreenLoading()
105→                }
106→                uiState.error != null && uiState.posts.isEmpty() -> {
107→                    ErrorMessage(
108→                        message = uiState.error ?: stringResource(R.string.error_generic),
109→                        onRetry = { viewModel.refresh() }
110→                    )
111→                }
112→                uiState.posts.isEmpty() -> {
113→                    ErrorMessage(
114→                        message = stringResource(R.string.no_posts),
115→                        icon = null
116→                    )
117→                }
118→                else -> {
119→                    PullToRefreshBox(
120→                        isRefreshing = uiState.isRefreshing,
121→                        onRefresh = { viewModel.refresh() }
122→                    ) {
123→                        LazyColumn(
124→                            state = listState
125→                        ) {
126→                            items(
127→                                items = uiState.posts,
128→                                key = { it.id }
129→                            ) { post ->
130→                                PostCard(
131→                                    post = post,
132→                                    onClick = { onPostClick(post.sharedPost?.id ?: post.id) },
133→                                    onProfileClick = onProfileClick,
134→                                    contentMaxLength = timelineMaxLength,
135→                                    onReplyClick = { onComposeClick(post.sharedPost?.id ?: post.id) },
136→                                    onShareClick = {
137→                                        if (post.viewerHasShared) {
138→                                            viewModel.unsharePost(post.id)
139→                                        } else {
140→                                            viewModel.sharePost(post.id)
141→                                        }
142→                                    },
143→                                    onQuoteClick = { onQuoteClick(post.sharedPost?.id ?: post.id) },
144→                                    onReactionClick = { onPostClick(post.sharedPost?.id ?: post.id) },
145→                                    onExternalShareClick = {
146→                                        val displayPost = post.sharedPost ?: post
147→                                        val shareUrl = displayPost.url ?: displayPost.iri
148→                                        if (shareUrl != null) {
149→                                            val sendIntent = Intent().apply {
150→                                                action = Intent.ACTION_SEND
151→                                                putExtra(Intent.EXTRA_TEXT, shareUrl)
152→                                                type = "text/plain"
153→                                            }
154→                                            context.startActivity(Intent.createChooser(sendIntent, null))
155→                                        }
156→                                    },
157→                                    onQuotedPostClick = onPostClick
158→                                )
159→                                HorizontalDivider(thickness = 0.5.dp)
160→                            }
161→
162→                            if (uiState.isLoadingMore) {
163→                                item {
164→                                    LoadingItem()
165→                                }
166→                            }
167→                        }
168→                    }
169→                }
170→            }
171→        }
172→    }
173→}
