 21→import androidx.compose.ui.unit.sp
 22→import java.net.URI
 23→
 24→val LocalFontScale = compositionLocalOf { 1f }
 25→
 26→private enum class LinkType {
 27→    MENTION, HASHTAG, REGULAR
 28→}
 29→
 30→private val TAG_REGEX = Regex("""<(/?)(\w+)([^>]*)>""")
 31→private val ATTR_REGEX = Regex("""([\w-]+)=["']([^"']*)["']""")
 32→
 33→@Composable
 34→fun HtmlContent(
 35→    html: String,
 36→    maxLines: Int = Int.MAX_VALUE,
 37→    modifier: Modifier = Modifier,
 38→    fontScale: Float = 1f,
 39→    onMentionClick: ((handle: String) -> Unit)? = null,
 40→    onLinkClick: ((url: String) -> Unit)? = null
 41→) {
 42→    val uriHandler = LocalUriHandler.current
 43→    val isDark = isSystemInDarkTheme()
 44→    val linkColor = if (isDark) Color(0xFF60A5FA) else Color(0xFF2563EB)
 45→    val mentionBg = linkColor.copy(alpha = 0.10f)
 46→    val textColor = MaterialTheme.colorScheme.onSurface
 47→
 48→    val annotatedString = remember(html, linkColor, mentionBg) {
 49→        parseHtmlToAnnotatedString(html, linkColor, mentionBg)
 50→    }
 51→
 52→    val effectiveFontScale = if (fontScale != 1f) fontScale else LocalFontScale.current
 53→    val baseStyle = MaterialTheme.typography.bodyMedium.copy(color = textColor)
 54→    val scaledStyle = if (effectiveFontScale != 1f) {
 55→        baseStyle.copy(fontSize = baseStyle.fontSize * effectiveFontScale)
 56→    } else baseStyle
 57→
 58→    ClickableText(
 59→        text = annotatedString,
 60→        style = scaledStyle,
 61→        maxLines = maxLines,
 62→        overflow = TextOverflow.Ellipsis,
 63→        modifier = modifier,
 64→        onClick = { offset ->
 65→            // Check mentions first
 66→            annotatedString.getStringAnnotations("MENTION", offset, offset)
 67→                .firstOrNull()?.let { annotation ->
 68→                    val handle = extractHandleFromUrl(annotation.item)
 69→                    if (handle != null && onMentionClick != null) {
 70→                        onMentionClick(handle)
 71→                    } else {
 72→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 73→                    }
 74→                    return@ClickableText
 75→                }
 76→
 77→            // Then regular links and hashtags
 78→            annotatedString.getStringAnnotations("URL", offset, offset)
 79→                .firstOrNull()?.let { annotation ->
 80→                    if (onLinkClick != null) {
 81→                        onLinkClick(annotation.item)
 82→                    } else {
 83→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 84→                    }
 85→                }
 86→        }
 87→    )
 88→}
 89→
 90→/**
 91→ * Extracts a fediverse handle from a mention URL.
 92→ * e.g. "https://hackers.pub/@user" -> "user@hackers.pub"
 93→ *      "https://mastodon.social/@user" -> "user@mastodon.social"
 94→ */
 95→private fun extractHandleFromUrl(url: String): String? {
 96→    return try {
 97→        val uri = URI(url)
 98→        val host = uri.host ?: return null
 99→        val path = uri.path ?: return null
100→        val username = path.trimStart('/').removePrefix("@")
101→        if (username.isNotEmpty()) "$username@$host" else null
102→    } catch (_: Exception) {
103→        null
104→    }
105→}
106→
107→private fun parseHtmlToAnnotatedString(
108→    html: String,
109→    linkColor: Color,
110→    mentionBg: Color
111→): AnnotatedString {
112→    return buildAnnotatedString {
113→        var currentLinkType: LinkType? = null
114→        var hasAnnotation = false
115→        var insideInvisibleSpan = false
116→        var invisibleSpanDepth = 0
117→        var hasContent = false
118→        var isBold = false
119→        var isItalic = false
120→        var isStrikethrough = false
121→        var isCode = false
122→        var isPreformatted = false
123→        var listDepth = 0
124→        var orderedListCounter = 0
125→        var isInList = false
126→        var isBlockquote = false
127→
128→        var pos = 0
129→        val source = html.trim()
130→
131→        while (pos < source.length) {
132→            val tagMatch = TAG_REGEX.find(source, pos)
133→
134→            // Handle text before the next tag (or remaining text if no more tags)
135→            if (tagMatch == null || tagMatch.range.first > pos) {
136→                val textEnd = tagMatch?.range?.first ?: source.length
137→                val rawText = source.substring(pos, textEnd)
138→                val decoded = decodeHtmlEntities(rawText)
139→
140→                if (!insideInvisibleSpan && decoded.isNotEmpty()) {
141→                    val isInterBlockWhitespace = decoded.isBlank() && decoded.contains('\n')
142→                    if (!isInterBlockWhitespace) {
143→                        val styledText = decoded
144→                        val inlineStyle = SpanStyle(
145→                            fontWeight = if (isBold) FontWeight.Bold else null,
146→                            fontStyle = if (isItalic) FontStyle.Italic else null,
147→                            textDecoration = if (isStrikethrough) TextDecoration.LineThrough else null,
148→                            fontFamily = if (isCode || isPreformatted) FontFamily.Monospace else null,
149→                            background = if (isCode && !isPreformatted) Color(0x20808080) else Color.Unspecified
150→                        )
151→
152→                        if (isBold || isItalic || isStrikethrough || isCode || isPreformatted) {
153→                            withStyle(inlineStyle) {
154→                                appendStyledText(this, styledText, currentLinkType, linkColor, mentionBg)
155→                            }
156→                        } else {
157→                            appendStyledText(this, styledText, currentLinkType, linkColor, mentionBg)
158→                        }
159→                        hasContent = true
160→                    }
161→                }
162→
163→                pos = textEnd
164→            }
165→
166→            if (tagMatch != null && tagMatch.range.first == pos) {
167→                val isClosing = tagMatch.groupValues[1] == "/"
168→                val tagName = tagMatch.groupValues[2].lowercase()
169→                val attrString = tagMatch.groupValues[3]
170→
171→                if (!isClosing) {
172→                    val attrs = parseAttributes(attrString)
173→
174→                    when (tagName) {
175→                        "p" -> {
176→                            if (hasContent) append("\n\n")
177→                        }
178→                        "br" -> {
179→                            append("\n")
180→                        }
181→                        "strong", "b" -> {
182→                            isBold = true
183→                        }
184→                        "em", "i" -> {
185→                            isItalic = true
186→                        }
187→                        "del", "s", "strike" -> {
188→                            isStrikethrough = true
189→                        }
190→                        "hr" -> {
191→                            if (hasContent) append("\n")
192→                            append("──────────")
193→                            append("\n")
194→                            hasContent = true
195→                        }
196→                        "code" -> {
197→                            isCode = true
198→                        }
199→                        "pre" -> {
200→                            if (hasContent) append("\n\n")
201→                            isPreformatted = true
202→                        }
203→                        "blockquote" -> {
204→                            if (hasContent) append("\n\n")
205→                            isBlockquote = true
206→                            append("  \u2502 ")
207→                        }
208→                        "ul" -> {
209→                            if (hasContent && listDepth == 0) append("\n")
210→                            listDepth++
211→                            isInList = true
212→                        }
213→                        "ol" -> {
214→                            if (hasContent && listDepth == 0) append("\n")
215→                            listDepth++
216→                            orderedListCounter = 0
217→                            isInList = true
218→                        }
219→                        "li" -> {
220→                            if (hasContent) append("\n")
221→                            val indent = "  ".repeat(listDepth)
222→                            if (orderedListCounter > 0 || tagName == "li") {
223→                                // Check parent — simple heuristic: if orderedListCounter was reset, it's unordered
224→                            }
225→                            append("${indent}\u2022 ")
226→                        }
227→                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
228→                            if (hasContent) append("\n\n")
229→                            isBold = true
230→                        }
231→                        "a" -> {
232→                            val classes = attrs["class"] ?: ""
233→                            val href = attrs["href"] ?: ""
234→
235→                            currentLinkType = when {
236→                                "hashtag" in classes -> LinkType.HASHTAG
237→                                "mention" in classes -> LinkType.MENTION
238→                                href.isNotEmpty() -> LinkType.REGULAR
239→                                else -> null
240→                            }
241→
242→                            if (href.isNotEmpty()) {
243→                                val tag = if (currentLinkType == LinkType.MENTION) "MENTION" else "URL"
244→                                pushStringAnnotation(tag, href)
245→                                hasAnnotation = true
246→                            }
247→                        }
248→                        "span" -> {
249→                            val classes = attrs["class"] ?: ""
250→                            if ("invisible" in classes) {
251→                                insideInvisibleSpan = true
252→                                invisibleSpanDepth++
253→                            }
254→                        }
255→                    }
256→                } else {
257→                    when (tagName) {
258→                        "strong", "b" -> {
259→                            isBold = false
260→                        }
261→                        "em", "i" -> {
262→                            isItalic = false
263→                        }
264→                        "del", "s", "strike" -> {
265→                            isStrikethrough = false
266→                        }
267→                        "code" -> {
268→                            isCode = false
269→                        }
270→                        "pre" -> {
271→                            isPreformatted = false
272→                            append("\n")
273→                        }
274→                        "blockquote" -> {
275→                            isBlockquote = false
276→                        }
277→                        "ul", "ol" -> {
278→                            listDepth = maxOf(0, listDepth - 1)
279→                            if (listDepth == 0) {
280→                                isInList = false
281→                                orderedListCounter = 0
282→                            }
283→                        }
284→                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
285→                            isBold = false
286→                            append("\n")
287→                        }
288→                        "a" -> {
289→                            if (hasAnnotation) {
290→                                pop()
291→                                hasAnnotation = false
292→                            }
293→                            currentLinkType = null
294→                        }
295→                        "span" -> {
296→                            if (insideInvisibleSpan) {
297→                                invisibleSpanDepth--
298→                                if (invisibleSpanDepth <= 0) {
299→                                    insideInvisibleSpan = false
300→                                    invisibleSpanDepth = 0
301→                                }
302→                            }
303→                        }
304→                    }
305→                }
306→
307→                pos = tagMatch.range.last + 1
308→            }
309→        }
310→    }
311→}
312→
313→private fun appendStyledText(
314→    builder: AnnotatedString.Builder,
315→    text: String,
316→    linkType: LinkType?,
317→    linkColor: Color,
318→    mentionBg: Color
319→) {
320→    when (linkType) {
321→        LinkType.MENTION -> {
322→            builder.withStyle(
323→                SpanStyle(
324→                    color = linkColor,
325→                    fontWeight = FontWeight.SemiBold,
326→                    background = mentionBg
327→                )
328→            ) {
329→                append(text)
330→            }
331→        }
332→        LinkType.HASHTAG -> {
333→            builder.withStyle(SpanStyle(color = linkColor)) {
334→                append(text)
335→            }
336→        }
337→        LinkType.REGULAR -> {
338→            builder.withStyle(
339→                SpanStyle(
340→                    color = linkColor,
341→                    textDecoration = TextDecoration.Underline
342→                )
343→            ) {
344→                append(text)
345→            }
346→        }
347→        null -> {
348→            builder.append(text)
349→        }
350→    }
351→}
352→
353→private fun parseAttributes(attrString: String): Map<String, String> {
354→    val attrs = mutableMapOf<String, String>()
355→    for (match in ATTR_REGEX.findAll(attrString)) {
356→        attrs[match.groupValues[1]] = match.groupValues[2]
357→    }
358→    return attrs
359→}
360→
361→private fun decodeHtmlEntities(text: String): String {
362→    return text
363→        .replace("&nbsp;", " ")
364→        .replace("&amp;", "&")
365→        .replace("&lt;", "<")
366→        .replace("&gt;", ">")
367→        .replace("&quot;", "\"")
368→        .replace("&#39;", "'")
369→        .replace("&apos;", "'")
370→}
