 50→        let urlPath = url.path
 51→        if urlPath.hasPrefix("/@") {
 52→            let handle = String(urlPath.dropFirst(2)) // Remove /@
 53→            navigationCoordinator.navigateToProfile(handle: handle)
 54→        }
