 140→    private func loadRelationship(cachePolicy: CachePolicy.Query.SingleResponse = .networkFirst) async {
 141→        guard let actorHandle else {
 142→            relationship = nil
 143→            return
 144→        }
 145→
 146→        do {
 147→            relationship = try await ActorRelationshipService.fetch(handle: actorHandle, cachePolicy: cachePolicy)
 148→        } catch {
 149→            relationship = nil
 150→        }
 151→    }
 152→
 153→    private func performRelationshipAction(_ action: ActorRelationshipAction, handle: String) {
 154→        guard authManager.isAuthenticated else { return }
 155→        guard !isApplyingRelationshipAction else { return }
 156→
 157→        Task {
 158→            isApplyingRelationshipAction = true
 159→            defer { isApplyingRelationshipAction = false }
 160→
 161→            do {
 162→                let currentRelationship: ActorRelationshipState
 163→                if let relationship {
 164→                    currentRelationship = relationship
 165→                } else if let fetched = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: .networkOnly) {
 166→                    currentRelationship = fetched
 167→                    self.relationship = fetched
 168→                } else {
 169→                    throw ActorRelationshipServiceError.actorNotFound
 170→                }
 171→
 172→                guard !currentRelationship.isViewer else { return }
 173→
 174→                try await ActorRelationshipService.perform(action: action, actorId: currentRelationship.actorId)
