 313→private struct ProfileSneakPeekModifier: ViewModifier {
 314→    let handle: String?
 315→    @Environment(AuthManager.self) private var authManager
 316→    @Environment(NavigationCoordinator.self) private var navigationCoordinator
 317→    @Environment(ExternalURLRouter.self) private var externalURLRouter
 318→    @State private var relationship: ActorRelationshipState?
 319→    @State private var relationshipActionErrorMessage: String?
 320→    @State private var isApplyingRelationshipAction = false
 321→
 322→    @ViewBuilder
 323→    func body(content: Content) -> some View {
 324→        if let handle {
 325→            content
 326→                .uiContextMenu(
 327→                    makeConfiguration: {
 328→                        makeProfileContextMenuConfiguration(handle: handle)
 329→                    },
 330→                    onCommit: {
 331→                        navigationCoordinator.navigateToProfile(handle: handle)
 332→                    }
 333→                )
 334→                .alert(
 335→                    NSLocalizedString("actorRelation.error.title", comment: "Actor relation action error title"),
 336→                    isPresented: Binding(
 337→                        get: { relationshipActionErrorMessage != nil },
 338→                        set: { isPresented in
 339→                            if !isPresented {
 340→                                relationshipActionErrorMessage = nil
 341→                            }
 342→                        }
 343→                    )
 344→                ) {
 345→                    Button(NSLocalizedString("compose.error.ok", comment: "OK button"), role: .cancel) {
 346→                        relationshipActionErrorMessage = nil
 347→                    }
 348→                } message: {
 349→                    Text(relationshipActionErrorMessage ?? "")
 350→                }
 351→        } else {
 352→            content
 353→        }
 354→    }
