 356→    private func loadRelationship(cachePolicy: CachePolicy.Query.SingleResponse = .networkFirst) async {
 357→        guard let handle else {
 358→            relationship = nil
 359→            return
 360→        }
 361→
 362→        do {
 363→            relationship = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: cachePolicy)
 364→        } catch {
 365→            relationship = nil
 366→        }
 367→    }
 368→
 369→    private func performRelationshipAction(_ action: ActorRelationshipAction, handle: String) {
 370→        guard authManager.isAuthenticated else { return }
 371→        guard !isApplyingRelationshipAction else { return }
 372→
 373→        Task {
 374→            isApplyingRelationshipAction = true
 375→            defer { isApplyingRelationshipAction = false }
 376→
 377→            do {
 378→                let currentRelationship: ActorRelationshipState
 379→                if let relationship {
 380→                    currentRelationship = relationship
 381→                } else if let fetched = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: .networkOnly) {
 382→                    currentRelationship = fetched
 383→                    self.relationship = fetched
 384→                } else {
 385→                    throw ActorRelationshipServiceError.actorNotFound
 386→                }
 387→
 388→                guard !currentRelationship.isViewer else { return }
 389→
 390→                try await ActorRelationshipService.perform(action: action, actorId: currentRelationship.actorId)
 391→                relationship = try await ActorRelationshipService.fetch(handle: handle, cachePolicy: .networkOnly)
 392→            } catch {
 393→                relationshipActionErrorMessage = error.localizedDescription
 394→            }
 395→        }
 396→    }
