1143→    private func applyReactionLocally(emoji: String, add: Bool) {
1144→        if let existingIndex = reactionGroups.firstIndex(where: { $0.emoji == emoji }) {
1145→            var group = reactionGroups[existingIndex]
1146→            let updatedCount = max(0, group.totalCount + (add ? 1 : -1))
1147→            if updatedCount == 0 {
1148→                reactionGroups.remove(at: existingIndex)
1149→            } else {
1150→                group.totalCount = updatedCount
1151→                group.viewerHasReacted = add
1152→                reactionGroups[existingIndex] = group
1153→            }
1154→        } else if add {
1155→            reactionGroups.append(
1156→                ReactionGroupSnapshot(
1157→                    id: "emoji:\(emoji)",
1158→                    emoji: emoji,
1159→                    customEmojiName: nil,
1160→                    customEmojiImageUrl: nil,
1161→                    totalCount: 1,
1162→                    viewerHasReacted: true
1163→                )
1164→            )
1165→        }
1166→        reactionsCount = max(0, reactionsCount + (add ? 1 : -1))
1167→    }
