103→    private func sendSignInLink() async {
104→        isLoading = true
105→        errorMessage = nil
106→        defer { isLoading = false }
107→
108→        do {
109→            // Use a simple URI template for the verification link
110→            // In a real app, this would be a deep link like myapp://verify?token={token}&code={code}
111→            let verifyUrl = "https://hackers.pub/verify?token={token}&code={code}"
112→
113→            let token = try await authManager.loginByUsername(
114→                username: username,
115→                verifyUrl: verifyUrl
116→            )
117→
118→            loginToken = token
119→            loginState = .enterCode
120→        } catch let error as AuthError {
121→            errorMessage = error.localizedDescription
122→        } catch {
123→            errorMessage = NSLocalizedString("signIn.unexpectedError", comment: "Unexpected error message")
124→        }
125→    }
126→
127→    private func verifyCode() async {
128→        guard let token = loginToken else { return }
129→
130→        isLoading = true
131→        errorMessage = nil
132→        defer { isLoading = false }
133→
134→        do {
135→            try await authManager.completeLoginChallenge(token: token, code: verificationCode)
136→            // Auth state will update automatically via @Observable
137→        } catch let error as AuthError {
138→            errorMessage = error.localizedDescription
139→        } catch {
140→            errorMessage = NSLocalizedString("signIn.unexpectedError", comment: "Unexpected error message")
141→        }
142→    }
143→}
