 47→@OptIn(ExperimentalMaterial3Api::class)
 48→@Composable
 49→fun ExploreScreen(
 50→    onPostClick: (String) -> Unit,
 51→    onProfileClick: (String) -> Unit,
 52→    onReplyClick: (String) -> Unit,
 53→    onQuoteClick: (String) -> Unit = {},
 54→    onComposeClick: () -> Unit = {},
 55→    onSignInClick: () -> Unit,
 56→    isLoggedIn: Boolean,
 57→    viewModel: ExploreViewModel = hiltViewModel()
 58→) {
 59→    val uiState by viewModel.uiState.collectAsState()
 60→    val listState = rememberLazyListState()
 61→    val context = LocalContext.current
 62→    val lifecycleOwner = LocalLifecycleOwner.current
 63→
 64→    DisposableEffect(lifecycleOwner) {
 65→        val observer = LifecycleEventObserver { _, event ->
 66→            if (event == Lifecycle.Event.ON_RESUME) {
 67→                viewModel.refreshIfStale()
 68→            }
 69→        }
 70→        lifecycleOwner.lifecycle.addObserver(observer)
 71→        onDispose { lifecycleOwner.lifecycle.removeObserver(observer) }
 72→    }
 73→
 74→    val shouldLoadMore by remember {
 75→        derivedStateOf {
 76→            val lastVisibleItem = listState.layoutInfo.visibleItemsInfo.lastOrNull()
 77→            lastVisibleItem != null && lastVisibleItem.index >= listState.layoutInfo.totalItemsCount - 3
 78→        }
 79→    }
 80→
 81→    LaunchedEffect(shouldLoadMore) {
 82→        if (shouldLoadMore && uiState.hasNextPage && !uiState.isLoadingMore) {
 83→            viewModel.loadMore()
 84→        }
 85→    }
 86→
 87→    LaunchedEffect(uiState.selectedTab) {
 88→        listState.scrollToItem(0)
 89→    }
 90→
 91→    Scaffold(
 92→        contentWindowInsets = WindowInsets(0),
 93→        topBar = {
 94→            CompactTopBar(
 95→                title = stringResource(R.string.nav_explore),
 96→                actions = {
 97→                    if (!isLoggedIn) {
 98→                        TextButton(onClick = onSignInClick) {
 99→                            Text(stringResource(R.string.sign_in))
100→                        }
101→                    }
102→                }
103→            )
104→        },
105→        floatingActionButton = {
106→            if (isLoggedIn) {
107→                FloatingActionButton(onClick = onComposeClick) {
108→                    Icon(
109→                        imageVector = Icons.Default.Add,
110→                        contentDescription = stringResource(R.string.compose)
111→                    )
112→                }
113→            }
114→        }
115→    ) { paddingValues ->
116→        Column(
117→            modifier = Modifier
118→                .fillMaxSize()
119→                .padding(paddingValues)
120→        ) {
121→            PrimaryTabRow(
122→                selectedTabIndex = uiState.selectedTab.ordinal
123→            ) {
124→                ExploreTab.entries.forEach { tab ->
125→                    Tab(
126→                        selected = uiState.selectedTab == tab,
127→                        onClick = { viewModel.selectTab(tab) },
128→                        text = {
129→                            Text(
130→                                when (tab) {
131→                                    ExploreTab.LOCAL -> stringResource(R.string.local_timeline)
132→                                    ExploreTab.GLOBAL -> stringResource(R.string.global_timeline)
133→                                }
134→                            )
135→                        }
136→                    )
137→                }
138→            }
139→
140→            Box(modifier = Modifier.fillMaxSize()) {
141→                when {
142→                    uiState.isLoading && uiState.posts.isEmpty() -> {
143→                        FullScreenLoading()
144→                    }
145→                    uiState.error != null && uiState.posts.isEmpty() -> {
146→                        ErrorMessage(
147→                            message = uiState.error ?: stringResource(R.string.error_generic),
148→                            onRetry = { viewModel.refresh() }
149→                        )
150→                    }
151→                    uiState.posts.isEmpty() -> {
152→                        ErrorMessage(
153→                            message = stringResource(R.string.no_posts)
154→                        )
155→                    }
156→                    else -> {
157→                        PullToRefreshBox(
158→                            isRefreshing = uiState.isRefreshing,
159→                            onRefresh = { viewModel.refresh() }
160→                        ) {
161→                            LazyColumn(
162→                                state = listState
163→                            ) {
164→                                items(
165→                                    items = uiState.posts,
166→                                    key = { it.id }
167→                                ) { post ->
168→                                    PostCard(
169→                                        post = post,
170→                                        onClick = { onPostClick(post.sharedPost?.id ?: post.id) },
171→                                        onProfileClick = onProfileClick,
172→                                        onReplyClick = if (isLoggedIn) {
173→                                            { onReplyClick(post.sharedPost?.id ?: post.id) }
174→                                        } else null,
175→                                        onShareClick = if (isLoggedIn) {
176→                                            {
177→                                                if (post.viewerHasShared) {
178→                                                    viewModel.unsharePost(post.id)
179→                                                } else {
180→                                                    viewModel.sharePost(post.id)
181→                                                }
182→                                            }
183→                                        } else null,
184→                                        onQuoteClick = if (isLoggedIn) {
185→                                            { onQuoteClick(post.sharedPost?.id ?: post.id) }
186→                                        } else null,
187→                                        onReactionClick = { onPostClick(post.sharedPost?.id ?: post.id) },
188→                                        onExternalShareClick = {
189→                                            val displayPost = post.sharedPost ?: post
190→                                            val shareUrl = displayPost.url ?: displayPost.iri
191→                                            if (shareUrl != null) {
192→                                                val sendIntent = Intent().apply {
193→                                                    action = Intent.ACTION_SEND
194→                                                    putExtra(Intent.EXTRA_TEXT, shareUrl)
195→                                                    type = "text/plain"
196→                                                }
197→                                                context.startActivity(Intent.createChooser(sendIntent, null))
198→                                            }
199→                                        },
200→                                        onQuotedPostClick = onPostClick
201→                                    )
202→                                    HorizontalDivider(thickness = 0.5.dp)
203→                                }
204→
205→                                if (uiState.isLoadingMore) {
206→                                    item {
207→                                        LoadingItem()
208→                                    }
209→                                }
210→                            }
211→                        }
212→                    }
213→                }
214→            }
215→        }
216→    }
217→}
