 24→val LocalFontScale = compositionLocalOf { 1f }
 25→
 26→private enum class LinkType {
 27→    MENTION, HASHTAG, REGULAR
 28→}
 29→
 30→private val TAG_REGEX = Regex("""<(/?)(\w+)([^>]*)>""")
 31→private val ATTR_REGEX = Regex("""([\w-]+)=["']([^"']*)["']""")
 32→
 33→@Composable
 34→fun HtmlContent(
 35→    html: String,
 36→    maxLines: Int = Int.MAX_VALUE,
 37→    modifier: Modifier = Modifier,
 38→    fontScale: Float = 1f,
 39→    onMentionClick: ((handle: String) -> Unit)? = null,
 40→    onLinkClick: ((url: String) -> Unit)? = null
 41→) {
 42→    val uriHandler = LocalUriHandler.current
 43→    val isDark = isSystemInDarkTheme()
 44→    val linkColor = if (isDark) Color(0xFF60A5FA) else Color(0xFF2563EB)
 45→    val mentionBg = linkColor.copy(alpha = 0.10f)
 46→    val textColor = MaterialTheme.colorScheme.onSurface
 47→
 48→    val annotatedString = remember(html, linkColor, mentionBg) {
 49→        parseHtmlToAnnotatedString(html, linkColor, mentionBg)
 50→    }
 51→
 52→    val effectiveFontScale = if (fontScale != 1f) fontScale else LocalFontScale.current
 53→    val baseStyle = MaterialTheme.typography.bodyMedium.copy(color = textColor)
 54→    val scaledStyle = if (effectiveFontScale != 1f) {
 55→        baseStyle.copy(fontSize = baseStyle.fontSize * effectiveFontScale)
 56→    } else baseStyle
 57→
 58→    ClickableText(
 59→        text = annotatedString,
 60→        style = scaledStyle,
 61→        maxLines = maxLines,
 62→        overflow = TextOverflow.Ellipsis,
 63→        modifier = modifier,
 64→        onClick = { offset ->
 65→            // Check mentions first
 66→            annotatedString.getStringAnnotations("MENTION", offset, offset)
 67→                .firstOrNull()?.let { annotation ->
 68→                    val handle = extractHandleFromUrl(annotation.item)
 69→                    if (handle != null && onMentionClick != null) {
 70→                        onMentionClick(handle)
 71→                    } else {
 72→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 73→                    }
 74→                    return@ClickableText
 75→                }
 76→
 77→            // Then regular links and hashtags
 78→            annotatedString.getStringAnnotations("URL", offset, offset)
 79→                .firstOrNull()?.let { annotation ->
 80→                    if (onLinkClick != null) {
 81→                        onLinkClick(annotation.item)
 82→                    } else {
 83→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 84→                    }
 85→                }
 86→        }
 87→    )
 88→}
