176→                            if (hasContent) append("\n\n")
177→                        }
178→                        "br" -> {
179→                            append("\n")
180→                        }
181→                        "strong", "b" -> {
182→                            isBold = true
183→                        }
184→                        "em", "i" -> {
185→                            isItalic = true
186→                        }
187→                        "del", "s", "strike" -> {
188→                            isStrikethrough = true
189→                        }
190→                        "hr" -> {
191→                            if (hasContent) append("\n")
192→                            append("──────────")
193→                            append("\n")
