206→                            append("  \u2502 ")
207→                        }
208→                        "ul" -> {
209→                            if (hasContent && listDepth == 0) append("\n")
210→                            listDepth++
211→                            isInList = true
212→                        }
213→                        "ol" -> {
214→                            if (hasContent && listDepth == 0) append("\n")
215→                            listDepth++
216→                            orderedListCounter = 0
217→                            isInList = true
218→                        }
219→                        "li" -> {
