260→                        }
261→                        "em", "i" -> {
262→                            isItalic = false
263→                        }
264→                        "del", "s", "strike" -> {
265→                            isStrikethrough = false
266→                        }
267→                        "code" -> {
268→                            isCode = false
269→                        }
270→                        "pre" -> {
271→                            isPreformatted = false
272→                            append("\n")
273→                        }
274→                        "blockquote" -> {
275→                            isBlockquote = false
276→                        }
277→                        "ul", "ol" -> {
278→                            listDepth = maxOf(0, listDepth - 1)
279→                            if (listDepth == 0) {
280→                                isInList = false
281→                                orderedListCounter = 0
282→                            }
283→                        }
284→                        "h1", "h2", "h3", "h4", "h5", "h6" -> {
