 81→                    if (onLinkClick != null) {
 82→                        onLinkClick(annotation.item)
 83→                    } else {
 84→                        try { uriHandler.openUri(annotation.item) } catch (_: Exception) {}
 85→                    }
 86→                }
 87→        }
 88→    )
