 91→/**
 92→ * Extracts a fediverse handle from a mention URL.
 93→ * e.g. "https://hackers.pub/@user" -> "user@hackers.pub"
 94→ *      "https://mastodon.social/@user" -> "user@mastodon.social"
 95→ */
 96→private fun extractHandleFromUrl(url: String): String? {
 97→    return try {
 98→        val uri = URI(url)
 99→        val host = uri.host ?: return null
100→        val path = uri.path ?: return null
101→        val username = path.trimStart('/').removePrefix("@")
102→        if (username.isNotEmpty()) "$username@$host" else null
103→    } catch (_: Exception) {
104→        null
105→    }
106→}
