334→        LinkType.HASHTAG -> {
335→            builder.withStyle(SpanStyle(color = linkColor)) {
336→                append(text)
337→            }
338→        }
339→        LinkType.REGULAR -> {
340→            builder.withStyle(
341→                SpanStyle(
342→                    color = linkColor,
343→                    textDecoration = TextDecoration.Underline
344→                )
345→            ) {
346→                append(text)
347→            }
348→        }
349→        null -> {
350→            builder.append(text)
351→        }
352→    }
353→}
354→
355→private fun parseAttributes(attrString: String): Map<String, String> {
356→    val attrs = mutableMapOf<String, String>()
357→    for (match in ATTR_REGEX.findAll(attrString)) {
358→        attrs[match.groupValues[1]] = match.groupValues[2]
359→    }
360→    return attrs
361→}
