363→private fun decodeHtmlEntities(text: String): String {
364→    return text
365→        .replace("&nbsp;", " ")
366→        .replace("&amp;", "&")
367→        .replace("&lt;", "<")
368→        .replace("&gt;", ">")
369→        .replace("&quot;", "\"")
370→        .replace("&#39;", "'")
371→        .replace("&apos;", "'")
372→}
